#include <bits/stdc++.h>
using namespace std;

int a[1000006];

int main()
{
    int n;
    cin >> n;
    for(int i = 1; i <= n; i++)
        cin >> a[i];
    sort(a + 1, a + n + 1);
    int ans = -2e9;
    for(int i = 1; i < n; i++)
        ans = max(ans, a[i] - a[i + 1]);
    cout << ans << endl;
}
